#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=505,M=100005;
int n,m,a[N],b[N],dp[M],num=1,ans[M];
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>m;
	for(int i=1;i<=n;i++) cin>>a[i]>>b[i];
	for(int i=1;i<=m;i++)
	{
		dp[i]=i;
		for(int j=1;j<=n;j++)
		{
			if(a[j]>i) continue;
			dp[i]=max(dp[i],a[j]+dp[i-a[j]+b[j]]);
		}
		while(dp[i]>=num)
		{
			ans[num]=i;
			num++;
			if(num>=m+1) break;
		}
		if(num>=m+1) break;
	}
	for(int i=1;i<=m;i++) cout<<ans[i]<<"\n";
	return 0;
}
